export const getRandomTFQuestions = (count: number): TFQuestion[] => {
  const pool = [...tfQuestions].sort(() => 0.5 - Math.random());
  if (count > pool.length) count = pool.length;
  
  const result: TFQuestion[] = [];
  const used = new Set<string>();
  
  for (let i = 0; i < count; i++) {
     let bestIdx = -1;
     for (let p = 0; p < pool.length; p++) {
        const candidate = pool[p];
        if (!used.has(candidate.question)) {
           const L = result.length;
           if (L >= 2) {
               if (result[L-1].category === candidate.category && result[L-2].category === candidate.category) {
                   continue; 
               }
           }
           bestIdx = p;
           break;
        }
     }
     
     if (bestIdx === -1) {
        for (let p = 0; p < pool.length; p++) {
           if (!used.has(pool[p].question)) {
              bestIdx = p;
              break;
           }
        }
     }
     
     if (bestIdx !== -1) {
       used.add(pool[bestIdx].question);
       result.push(pool[bestIdx]);
     } else {
       break;
     }
  }

  return result;
};
